package com.ruoyi.web.controller.mes; import com.ruoyi.common.core.controller.BaseController; import com.ruoyi.common.core.domain.AjaxResult; import com.ruoyi.common.core.page.TableDataInfo; import com.ruoyi.mes.purchase.domain.PurchaseInbound; import com.ruoyi.mes.purchase.mapper.PurchaseInboundMapper; import org.springframework.web.bind.annotation.*; import java.util.Arrays;
@RestController @RequestMapping("/mes/purchase/inbound") public class PurchaseInboundController extends BaseController { private final PurchaseInboundMapper mapper; public PurchaseInboundController(PurchaseInboundMapper mapper){this.mapper=mapper;} @GetMapping("/list") public TableDataInfo list(PurchaseInbound q){startPage();return getDataTable(mapper.selectList(q));} @GetMapping("/{id}") public AjaxResult get(@PathVariable Long id){PurchaseInbound o=mapper.selectById(id);if(o!=null)o.setLines(mapper.selectLines(id));return success(o);} @PostMapping public AjaxResult add(@RequestBody PurchaseInbound o){o.setCreateBy(getUsername());mapper.insert(o);if(o.getLines()!=null)o.getLines().forEach(x->{x.setInboundId(o.getId());mapper.insertLine(x);});return success(o.getId());} @PutMapping public AjaxResult edit(@RequestBody PurchaseInbound o){o.setUpdateBy(getUsername());return toAjax(mapper.update(o));} @DeleteMapping("/{ids}") public AjaxResult remove(@PathVariable Long[] ids){mapper.deleteLines(Arrays.asList(ids));return toAjax(mapper.deleteByIds(ids));} }
